import React, { useState, useEffect } from 'react';
import { logMood, getMoodHistory, getMoodStats } from '../api';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { format } from 'date-fns';

const MOODS = [
  { score: 1, emoji: '😭', label: 'Terrible' },
  { score: 2, emoji: '😞', label: 'Very Bad' },
  { score: 3, emoji: '😟', label: 'Bad' },
  { score: 4, emoji: '😕', label: 'Not Great' },
  { score: 5, emoji: '😐', label: 'Okay' },
  { score: 6, emoji: '🙂', label: 'Decent' },
  { score: 7, emoji: '😊', label: 'Good' },
  { score: 8, emoji: '😄', label: 'Great' },
  { score: 9, emoji: '😁', label: 'Excellent' },
  { score: 10, emoji: '🤩', label: 'Amazing' },
];

export default function MoodTracker() {
  const [form, setForm] = useState({ mood_score: 5, stress_level: 3, anxiety_level: 3, sleep_hours: 7, notes: '' });
  const [history, setHistory] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  const loadData = () => {
    getMoodHistory(14).then(r => setHistory(r.data || [])).catch(() => {});
    getMoodStats().then(r => setStats(r.data || null)).catch(() => {});
  };
  useEffect(() => { loadData(); }, []);

  const submit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await logMood(form);
      setSuccess(true);
      loadData();
      setTimeout(() => setSuccess(false), 3000);
    } catch {} finally { setLoading(false); }
  };

  const chartData = [...history].reverse().map(h => ({
    date: format(new Date(h.logged_at), 'MMM d'),
    mood: h.mood_score,
    stress: h.stress_level,
    anxiety: h.anxiety_level,
  }));

  const selectedMood = MOODS.find(m => m.score === form.mood_score);

  return (
    <div style={styles.page}>
      <h1 style={styles.title}>Mood Tracker</h1>
      <p style={styles.subtitle}>Log how you're feeling to spot patterns and understand yourself better.</p>

      <div style={styles.grid}>
        {/* Log form */}
        <div className="card" style={styles.formCard}>
          <h2 style={styles.cardTitle}>How are you feeling?</h2>

          {success && <div style={styles.successBox}>✅ Mood logged successfully!</div>}

          <form onSubmit={submit} style={styles.form}>
            {/* Mood score */}
            <div style={styles.moodDisplay}>
              <span style={styles.moodEmoji}>{selectedMood?.emoji}</span>
              <span style={styles.moodLabel}>{selectedMood?.label}</span>
              <span style={styles.moodScore}>{form.mood_score}/10</span>
            </div>
            <input type="range" min="1" max="10" value={form.mood_score}
              onChange={e => setForm(f => ({ ...f, mood_score: parseInt(e.target.value) }))}
              style={styles.slider} />
            <div style={styles.sliderLabels}><span>Terrible</span><span>Amazing</span></div>

            {/* Sliders */}
            <SliderField label="😰 Stress Level" value={form.stress_level} min={1} max={5}
              onChange={v => setForm(f => ({ ...f, stress_level: v }))} color="var(--amber)" />
            <SliderField label="😟 Anxiety Level" value={form.anxiety_level} min={1} max={5}
              onChange={v => setForm(f => ({ ...f, anxiety_level: v }))} color="var(--rose)" />
            <SliderField label="💤 Sleep Hours" value={form.sleep_hours} min={0} max={12} step={0.5}
              onChange={v => setForm(f => ({ ...f, sleep_hours: v }))} color="var(--teal)" unit="hrs" />

            {/* Notes */}
            <div style={styles.field}>
              <label style={styles.label}>Notes (optional)</label>
              <textarea value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))}
                className="input-field" rows={3} placeholder="What's influencing your mood today?" style={{ resize: 'vertical' }} />
            </div>

            <button type="submit" className="btn-primary" style={{ width: '100%' }} disabled={loading}>
              {loading ? 'Saving…' : '📊 Log My Mood'}
            </button>
          </form>
        </div>

        {/* Stats */}
        <div style={styles.statsCol}>
          {stats && (
            <div style={styles.statsGrid}>
              <MiniStat label="Avg Mood" value={parseFloat(stats.avg_mood || 0).toFixed(1)} max="/10" color="var(--sage)" />
              <MiniStat label="Avg Stress" value={parseFloat(stats.avg_stress || 0).toFixed(1)} max="/5" color="var(--amber)" />
              <MiniStat label="Avg Sleep" value={parseFloat(stats.avg_sleep || 0).toFixed(1)} max="hrs" color="var(--teal)" />
              <MiniStat label="Entries" value={stats.total_logs || 0} max="" color="var(--rose)" />
            </div>
          )}

          {chartData.length > 1 && (
            <div className="card">
              <h3 style={styles.chartTitle}>Mood Over Time</h3>
              <ResponsiveContainer width="100%" height={180}>
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="moodGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#7C9E8A" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#7C9E8A" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke="#E8F0ED" />
                  <XAxis dataKey="date" tick={{ fontSize: 11, fill: '#8FA8A5' }} />
                  <YAxis domain={[0, 10]} tick={{ fontSize: 11, fill: '#8FA8A5' }} />
                  <Tooltip contentStyle={{ borderRadius: 10, border: '1px solid var(--border)', fontSize: 12 }} />
                  <Area type="monotone" dataKey="mood" stroke="#7C9E8A" strokeWidth={2} fill="url(#moodGrad)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          )}

          {chartData.length > 1 && (
            <div className="card" style={{ marginTop: 16 }}>
              <h3 style={styles.chartTitle}>Stress & Anxiety</h3>
              <ResponsiveContainer width="100%" height={160}>
                <LineChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#E8F0ED" />
                  <XAxis dataKey="date" tick={{ fontSize: 11, fill: '#8FA8A5' }} />
                  <YAxis domain={[0, 5]} tick={{ fontSize: 11, fill: '#8FA8A5' }} />
                  <Tooltip contentStyle={{ borderRadius: 10, border: '1px solid var(--border)', fontSize: 12 }} />
                  <Line type="monotone" dataKey="stress" stroke="#E8A87C" strokeWidth={2} dot={false} name="Stress" />
                  <Line type="monotone" dataKey="anxiety" stroke="#E07B8A" strokeWidth={2} dot={false} name="Anxiety" />
                </LineChart>
              </ResponsiveContainer>
            </div>
          )}
        </div>
      </div>

      {/* History */}
      {history.length > 0 && (
        <div className="card" style={{ marginTop: 24 }}>
          <h2 style={styles.cardTitle}>Recent Entries</h2>
          <div style={styles.historyList}>
            {history.slice(0, 7).map(h => (
              <div key={h.id} style={styles.historyItem}>
                <div style={styles.historyLeft}>
                  <span style={{ fontSize: 22 }}>{MOODS.find(m => m.score === h.mood_score)?.emoji || '😐'}</span>
                  <div>
                    <div style={styles.historyDate}>{format(new Date(h.logged_at), 'MMM d, yyyy · h:mm a')}</div>
                    {h.notes && <div style={styles.historyNote}>{h.notes}</div>}
                  </div>
                </div>
                <div style={styles.historyRight}>
                  <span style={styles.historyScore}>{h.mood_score}/10</span>
                  <span style={styles.historyMoodLabel}>{h.mood_label}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function SliderField({ label, value, min, max, step = 1, onChange, color, unit = '' }) {
  return (
    <div style={{ marginBottom: 16 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
        <label style={{ fontSize: '0.88rem', fontWeight: 500, color: 'var(--ink-light)' }}>{label}</label>
        <span style={{ fontSize: '0.88rem', fontWeight: 700, color }}>{value}{unit}</span>
      </div>
      <input type="range" min={min} max={max} step={step} value={value}
        onChange={e => onChange(parseFloat(e.target.value))}
        style={{ ...styles.slider, accentColor: color }} />
    </div>
  );
}

function MiniStat({ label, value, max, color }) {
  return (
    <div className="card" style={{ textAlign: 'center', padding: 16, borderColor: 'transparent', background: 'var(--surface)' }}>
      <div style={{ fontSize: '1.4rem', fontWeight: 700, color, fontFamily: 'var(--font-serif)' }}>{value}<span style={{ fontSize: '0.75rem', color: 'var(--mist)' }}>{max}</span></div>
      <div style={{ fontSize: '0.75rem', color: 'var(--mist)', marginTop: 2 }}>{label}</div>
    </div>
  );
}

const styles = {
  page: { maxWidth: 1000, margin: '0 auto' },
  title: { fontSize: '2rem', marginBottom: 6 },
  subtitle: { color: 'var(--mist)', marginBottom: 28 },
  grid: { display: 'grid', gridTemplateColumns: '1fr 1.1fr', gap: 24, alignItems: 'start' },
  formCard: {},
  cardTitle: { fontSize: '1.2rem', marginBottom: 20 },
  successBox: { background: '#E8F5E9', color: '#2E7D32', border: '1px solid #A5D6A7', padding: '10px 14px', borderRadius: 'var(--radius-sm)', marginBottom: 16, fontSize: '0.9rem' },
  form: { display: 'flex', flexDirection: 'column' },
  moodDisplay: { textAlign: 'center', marginBottom: 12 },
  moodEmoji: { fontSize: 52, display: 'block' },
  moodLabel: { display: 'block', fontWeight: 700, color: 'var(--ink)', fontSize: '1.1rem' },
  moodScore: { display: 'block', color: 'var(--mist)', fontSize: '0.85rem' },
  slider: { width: '100%', accentColor: 'var(--sage)', marginBottom: 6 },
  sliderLabels: { display: 'flex', justifyContent: 'space-between', fontSize: '0.75rem', color: 'var(--mist)', marginBottom: 20 },
  field: { marginBottom: 16 },
  label: { fontSize: '0.85rem', fontWeight: 600, color: 'var(--ink-light)', display: 'block', marginBottom: 6 },
  statsCol: { display: 'flex', flexDirection: 'column', gap: 16 },
  statsGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 },
  chartTitle: { fontSize: '0.95rem', marginBottom: 12, color: 'var(--ink)' },
  historyList: { display: 'flex', flexDirection: 'column' },
  historyItem: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px 0', borderBottom: '1px solid var(--border)' },
  historyLeft: { display: 'flex', alignItems: 'center', gap: 12 },
  historyDate: { fontWeight: 500, fontSize: '0.88rem', color: 'var(--ink)' },
  historyNote: { fontSize: '0.8rem', color: 'var(--mist)', marginTop: 2 },
  historyRight: { textAlign: 'right' },
  historyScore: { fontWeight: 700, color: 'var(--teal)', display: 'block' },
  historyMoodLabel: { fontSize: '0.78rem', color: 'var(--mist)' },
};
